Component Name: UPI QR Code Payment. Category: Payment. Description: . Keywords: . Code: import React, { useState } from 'react';

interface UPIPaymentProps {
  upiId: string;
  amount: string;
  merchantName: string;
}

const UPIPayment: React.FC<UPIPaymentProps> = ({ upiId = 'merchant@paytm', amount, merchantName }) => {
