  const copyUPI = () => {
    navigator.clipboard.writeText(upiId);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const qrCodeUrl = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=upi://pay?pa=${upiId}&pn=${encodeURIComponent(merchantName)}&am=${amount}&cu=INR`;

  return (
    <div style={{
      padding: '40px',
      maxWidth: '450px',
      margin: '0 auto',
      backgroundColor: '#ffffff',
      borderRadius: '20px',
      boxShadow: '0 10px 40px rgba(0,0,0,0.1)',
      textAlign: 'center',
      fontFamily: 'system-ui, -apple-system, sans-serif'
    }}>
      <h2 style={{ fontSize: '28px', fontWeight: 'bold', marginBottom: '10px', color: '#1a1a1a' }}>Pay with UPI</h2>
      <p style={{ fontSize: '42px', fontWeight: 'bold', color: '#10b981', marginBottom: '24px' }}>₹{amount}</p>

      <div style={{
        padding: '20px',
        backgroundColor: '#f9fafb',
        borderRadius: '16px',
        marginBottom: '24px'
      }}>
        <img 
          src={qrCodeUrl}
          alt="UPI QR Code"
          style={{
            width: '280px',
            height: '280px',
            border: '4px solid #e5e7eb',
            borderRadius: '12px',
            margin: '0 auto',
            display: 'block'
          }}
        />
        <p style={{ marginTop: '16px', fontSize: '14px', color: '#6b7280' }}>Scan with any UPI app</p>
      </div>

      <div style={{
        padding: '16px',
        backgroundColor: '#f3f4f6',
        borderRadius: '12px',
        marginBottom: '16px'
      }}>
        <p style={{ fontSize: '12px', color: '#6b7280', marginBottom: '8px' }}>UPI ID</p>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px' }}>
          <p style={{ fontSize: '16px', fontWeight: '600', color: '#1a1a1a' }}>{upiId}</p>
          <button
            onClick={copyUPI}
            style={{
              padding: '6px 12px',
