              color: copied ? '#10b981' : '#2563eb',
              backgroundColor: 'transparent',
              border: `1px solid ${copied ? '#10b981' : '#2563eb'}`,
              borderRadius: '6px',
              cursor: 'pointer',
              transition: 'all 0.2s'
            }}
          >
            {copied ? '✓ Copied' : '📋 Copy'}
