        </div>
      </div>

      <div style={{ display: 'flex', gap: '12px', marginTop: '20px' }}>
        <button style={{
          flex: 1,
          padding: '12px',
          fontSize: '14px',
          fontWeight: '600',
          color: '#ffffff',
          backgroundColor: '#7c3aed',
          border: 'none',
          borderRadius: '10px',
          cursor: 'pointer'
        }}>
          PhonePe
        </button>
        <button style={{
          flex: 1,
          padding: '12px',
          fontSize: '14px',
          fontWeight: '600',
          color: '#ffffff',
          backgroundColor: '#0ea5e9',
          border: 'none',
          borderRadius: '10px',
