Component Name: Order Summary with Payment. Category: Payment. Description: . Keywords: . Code: import React, { useState } from 'react';

interface OrderItem {
  id: number;
  name: string;
  price: number;
  quantity: number;
  image: string;
}

const OrderSummary: React.FC = () => {
  const [items] = useState<OrderItem[]>([
    { id: 1, name: 'Premium Product', price: 1999, quantity: 1, image: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=200' },
    { id: 2, name: 'Accessory Pack', price: 499, quantity: 2, image: 'https://images.unsplash.com/photo-1523275335684-37898b6baf30?w=200' }
  ]);

  const subtotal = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const shipping = 99;
  const tax = Math.round(subtotal * 0.18);
  const total = subtotal + shipping + tax;

  const handlePayment = (method: string) => {
    const paymentLinks: Record<string, string> = {
      upi: `upi://pay?pa=merchant@paytm&pn=Store&am=${total}&cu=INR`,
      razorpay: 'https://razorpay.me/@yourhandle',
      paypal: 'https://paypal.me/yourhandle'
    };

    if (method === 'upi' && /Android|iPhone/i.test(navigator.userAgent)) {
      window.location.href = paymentLinks[method];
    } else {
      window.open(paymentLinks[method] || paymentLinks.razorpay, '_blank');
    }
  };

  return (
    <div style={{
      maxWidth: '800px',
      margin: '40px auto',
      padding: '32px',
      backgroundColor: '#ffffff',
      borderRadius: '20px',
      boxShadow: '0 10px 40px rgba(0,0,0,0.08)',
      fontFamily: 'system-ui, -apple-system, sans-serif'
    }}>
      <h1 style={{ fontSize: '32px', fontWeight: 'bold', marginBottom: '32px', color: '#1a1a1a' }}>Order Summary</h1>

      <div style={{ marginBottom: '32px' }}>
        {items.map(item => (
          <div key={item.id} style={{
            display: 'flex',
            alignItems: 'center',
            gap: '16px',
            padding: '16px',
            backgroundColor: '#f9fafb',
            borderRadius: '12px',
            marginBottom: '12px'
          }}>
            <img src={item.image} alt={item.name} style={{ width: '80px', height: '80px', borderRadius: '8px', objectFit: 'cover' }} />
            <div style={{ flex: 1 }}>
              <h3 style={{ fontSize: '18px', fontWeight: '600', color: '#1a1a1a', marginBottom: '4px' }}>{item.name}</h3>
              <p style={{ fontSize: '14px', color: '#6b7280' }}>Quantity: {item.quantity}</p>
            </div>
            <p style={{ fontSize: '20px', fontWeight: 'bold', color: '#1a1a1a' }}>₹{item.price * item.quantity}</p>
          </div>
        ))}
      </div>

      <div style={{
        padding: '24px',
        backgroundColor: '#f9fafb',
        borderRadius: '16px',
        marginBottom: '32px'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '12px' }}>
          <span style={{ color: '#6b7280' }}>Subtotal</span>
